import{_ as n,H as a,f as p,i as l}from"./chunks/framework.BHvCMIhP.js";const h=JSON.parse('{"title":"可观测性是什么:监控 ≠ 可观测性 / 三件套 + Profile / Cardinality 陷阱","description":"","frontmatter":{},"headers":[],"relativePath":"devopsLearning/03-可观测性是什么.md","filePath":"devopsLearning/03-可观测性是什么.md","lastUpdated":1778496697000}'),e={name:"devopsLearning/03-可观测性是什么.md"};function i(t,s,c,o,r,u){return a(),p("div",null,[...s[0]||(s[0]=[l(`<h1 id="可观测性是什么-监控-可观测性-三件套-profile-cardinality-陷阱" tabindex="-1">可观测性是什么:监控 ≠ 可观测性 / 三件套 + Profile / Cardinality 陷阱 <a class="header-anchor" href="#可观测性是什么-监控-可观测性-三件套-profile-cardinality-陷阱" aria-label="Permalink to &quot;可观测性是什么:监控 ≠ 可观测性 / 三件套 + Profile / Cardinality 陷阱&quot;">​</a></h1><p>讲可观测性最大的混乱来自:<strong>业界把&quot;Observability&quot;用成了&quot;高级版的 Monitoring&quot;——卖工具的厂商懒得讲两者的真正区别,买工具的客户也懒得弄清楚</strong>。结果就是大家以为&quot;装了 Prometheus + Loki + Jaeger 三件套就是上了 Observability&quot;,<strong>实际上很多团队装了三件套,出事的时候还是只会&quot;ssh 上去 tail -f log&quot;</strong>。可观测性不是&quot;装了什么工具&quot;,是&quot;系统出新问题时,你能不能现场问出来&quot;——这个能力跟工具数量没有直接关系,<strong>跟你怎么&quot;埋点 + 关联 + 查询&quot;才有关系</strong>。这一篇就讲清楚:<strong>Monitoring 和 Observability 到底差在哪、三件套各自的边界、为什么 user_id 当 label 让 Prometheus 挂掉、可观测性的 3 个心智</strong>。</p><blockquote><p>一句话先记住:<strong>Monitoring 回答&quot;已知的未知&quot;(known unknowns)——我提前知道要问什么,把那个问题做成 dashboard 和告警;Observability 回答&quot;未知的未知&quot;(unknown unknowns)——系统出新问题时,我能现场问出来</strong>。前者是&quot;探照灯&quot;,照亮你提前指好的地方;后者是&quot;你能在黑暗里摸索的能力&quot;。<strong>一个团队&quot;装了多少工具&quot;决定不了 Observability,&quot;出事时能不能 5 分钟定位根因&quot;才决定</strong>。这一篇是这个系列的第二层(05-12 共 8 篇)的&quot;入门票&quot;——看完才知道为什么后面要花 8 篇讲 Metrics / Logs / Traces / Profile。</p></blockquote><hr><h2 id="一、问题场景-有-监控-没-可观测性-的团队长什么样" tabindex="-1">一、问题场景:有&quot;监控&quot;没&quot;可观测性&quot;的团队长什么样 <a class="header-anchor" href="#一、问题场景-有-监控-没-可观测性-的团队长什么样" aria-label="Permalink to &quot;一、问题场景:有&quot;监控&quot;没&quot;可观测性&quot;的团队长什么样&quot;">​</a></h2><h3 id="_1-1-一个真实的反面教材" tabindex="-1">1.1 一个真实的反面教材 <a class="header-anchor" href="#_1-1-一个真实的反面教材" aria-label="Permalink to &quot;1.1 一个真实的反面教材&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>团队 12 人,微服务 80 个,Prometheus + Grafana + ELK 都装了</span></span>
<span class="line"><span>看着挺像&quot;现代化&quot;了,但实际:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>凌晨 02:30,P0 告警:订单服务 P99 飙到 8 秒</span></span>
<span class="line"><span>值班工程师老李打开 Grafana:</span></span>
<span class="line"><span>   - 翻 30 个订单服务相关的 dashboard,只有 P99 是红的</span></span>
<span class="line"><span>   - 没有 latency 的&quot;按下游服务分组&quot;视图</span></span>
<span class="line"><span>   - 没有 trace 数据(链路追踪没接)</span></span>
<span class="line"><span>   - 看了 30 分钟,只能确认&quot;是慢了,不知道为什么&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>老李切到 Kibana:</span></span>
<span class="line"><span>   - 输入 &quot;service:order AND status:slow&quot;</span></span>
<span class="line"><span>   - 7,000 条日志,翻不完</span></span>
<span class="line"><span>   - 也不知道这 7000 条里哪一条是&quot;慢&quot;的代表</span></span>
<span class="line"><span>   - 想筛某个特定慢请求的 trace,但日志里没 trace_id</span></span>
<span class="line"><span></span></span>
<span class="line"><span>老李 ssh 到一台机器:</span></span>
<span class="line"><span>   - top:CPU 50%,看着不饱和</span></span>
<span class="line"><span>   - 但实际 GC 时间高 —— Prometheus 没采 JVM 指标</span></span>
<span class="line"><span>   - 实际下游 RDS 慢 —— 但没人监控 RDS 的 P99 查询时间</span></span>
<span class="line"><span></span></span>
<span class="line"><span>老李 03:30 之后开始猜:</span></span>
<span class="line"><span>   - 重启服务,P99 短暂下降,5 分钟后回升</span></span>
<span class="line"><span>   - 改并发参数,无效</span></span>
<span class="line"><span>   - 04:15 凭直觉判断&quot;可能是某个下游 RPC 慢&quot;,降级了一个非核心调用</span></span>
<span class="line"><span>   - 偶然恢复,不知道为什么</span></span>
<span class="line"><span></span></span>
<span class="line"><span>04:30 事故&quot;恢复&quot;,写复盘:</span></span>
<span class="line"><span>   &quot;根因不明,推测是下游某服务异常,已降级&quot;</span></span></code></pre></div><p><strong>这个团队装了 Prometheus / Grafana / ELK 三件套,看着挺现代化,但本质上还是&quot;靠老李的直觉 + 运气&quot;</strong>。<strong>这就是&quot;有监控没可观测性&quot;的真实长相——工具堆了,但出事时还是黑盒</strong>。</p><h3 id="_1-2-这个场景的根本问题" tabindex="-1">1.2 这个场景的根本问题 <a class="header-anchor" href="#_1-2-这个场景的根本问题" aria-label="Permalink to &quot;1.2 这个场景的根本问题&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>不是 Prometheus 不够强</span></span>
<span class="line"><span>   → 它能采的指标都采了</span></span>
<span class="line"><span></span></span>
<span class="line"><span>不是 ELK 不够全</span></span>
<span class="line"><span>   → 日志全在里面,7000 条 / 分钟也接得住</span></span>
<span class="line"><span></span></span>
<span class="line"><span>不是工程师不够强</span></span>
<span class="line"><span>   → 老李在 SRE 行业 8 年了</span></span>
<span class="line"><span></span></span>
<span class="line"><span>是 &quot;可观测性&quot;的工程动作没做:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  问题 1:数据之间没有&quot;关联键&quot;</span></span>
<span class="line"><span>    - Metrics、Logs、Traces 各自存在</span></span>
<span class="line"><span>    - 看到 P99 飙高 → 不知道哪条日志是这次慢的</span></span>
<span class="line"><span>    - 看到日志慢 → 不知道这次请求经过了哪些下游</span></span>
<span class="line"><span>    → 三件套各自孤立,看不到&quot;全链路视图&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  问题 2:维度不够细</span></span>
<span class="line"><span>    - dashboard 是预设的,只显示&quot;整体 P99&quot;</span></span>
<span class="line"><span>    - 不能现场&quot;按下游分组&quot;、&quot;按 user_id 范围分组&quot;</span></span>
<span class="line"><span>    - 现场需要的视角必须现场建,但建不出来</span></span>
<span class="line"><span>    → 这就是&quot;未知的未知&quot;问题</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  问题 3:数据采集面不够广</span></span>
<span class="line"><span>    - JVM 指标没采</span></span>
<span class="line"><span>    - RDS 慢查询日志没接</span></span>
<span class="line"><span>    - K8s 节点的 IO Wait 没看</span></span>
<span class="line"><span>    → 真正能解释根因的数据不在系统里</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  问题 4:查询能力弱</span></span>
<span class="line"><span>    - 7000 条日志没法&quot;按 trace 聚合&quot;</span></span>
<span class="line"><span>    - PromQL 不会写复杂关联</span></span>
<span class="line"><span>    → 数据在那里,但取不出来</span></span></code></pre></div><p><strong>这四个问题加起来,就是&quot;装了三件套但没做可观测性&quot;的核心症状</strong>。</p><h3 id="_1-3-中型团队踩这种坑的频率" tabindex="-1">1.3 中型团队踩这种坑的频率 <a class="header-anchor" href="#_1-3-中型团队踩这种坑的频率" aria-label="Permalink to &quot;1.3 中型团队踩这种坑的频率&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>团队规模 / 服务数      可观测性问题严重程度</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt; 5 人 / &lt; 10 服务      △ 还能靠&quot;全在脑子里&quot;</span></span>
<span class="line"><span>5-10 人 / 10-50 服务    ⚠ 临界点,装了工具但用不熟</span></span>
<span class="line"><span>10-30 人 / 50-200 服务  🔴 必崩,工具装了但不解决问题</span></span>
<span class="line"><span>&gt; 30 人 / &gt; 200 服务    🔥 全员痛苦,但已经投入巨大改造成本</span></span></code></pre></div><p><strong>5-10 人 / 50 服务</strong>这个阶段最危险——已经过了&quot;靠脑子记&quot;的体量,但还没认真做过可观测性工程,<strong>最容易出&quot;装了工具但出事还是抓瞎&quot;的尴尬场面</strong>。本系列服务的中型团队(10 人 / 100 微服务 / 5000 QPS)正好踩在这个坑上。</p><hr><h2 id="二、monitoring-vs-observability-本质差别" tabindex="-1">二、Monitoring vs Observability:本质差别 <a class="header-anchor" href="#二、monitoring-vs-observability-本质差别" aria-label="Permalink to &quot;二、Monitoring vs Observability:本质差别&quot;">​</a></h2><p>这两个词看起来像&quot;近义词&quot;,<strong>实际是两种不同的思维方式</strong>。</p><h3 id="_2-1-一个比喻-探照灯-vs-在黑暗里的眼睛" tabindex="-1">2.1 一个比喻:探照灯 vs 在黑暗里的眼睛 <a class="header-anchor" href="#_2-1-一个比喻-探照灯-vs-在黑暗里的眼睛" aria-label="Permalink to &quot;2.1 一个比喻:探照灯 vs 在黑暗里的眼睛&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Monitoring(监控)= 探照灯</span></span>
<span class="line"><span>                              ╲│╱</span></span>
<span class="line"><span>                            ── O ──   ← 探照灯</span></span>
<span class="line"><span>                              ╱│╲</span></span>
<span class="line"><span>                          ┌────┴────┐</span></span>
<span class="line"><span>                          │ ╱ ╲ ╱ ╲ │</span></span>
<span class="line"><span>                          │ 亮  亮  │</span></span>
<span class="line"><span>                          │/ ╱ ╲ ╱ ╲ \\│</span></span>
<span class="line"><span>                          ───────────</span></span>
<span class="line"><span>                          ░░░░░░░░░░░ ← 暗处看不见</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   提前指好探照灯的方向 → 那个方向看得很清楚</span></span>
<span class="line"><span>   暗处发生事情 → 你完全看不见</span></span>
<span class="line"><span>   出新问题 → 探照灯没指到 → 黑盒</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Observability(可观测性)= 在黑暗里的眼睛 + 手电</span></span>
<span class="line"><span>                              ╲│╱</span></span>
<span class="line"><span>                              👁️    ← 你的&quot;眼睛&quot;(查询能力)</span></span>
<span class="line"><span>                              ╱ ╲</span></span>
<span class="line"><span>                         ┌────────────┐</span></span>
<span class="line"><span>                         │ 任何方向都  │</span></span>
<span class="line"><span>                         │ 能现场探索  │</span></span>
<span class="line"><span>                         │            │</span></span>
<span class="line"><span>                         └────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   不预先指方向,你拥有&quot;现场探索任何地方&quot;的能力</span></span>
<span class="line"><span>   出新问题 → 现场问出来 → 即使没预设也能查</span></span></code></pre></div><p><strong>这个比喻的精髓</strong>:Monitoring 是&quot;我事先知道要问什么,把答案做成图&quot;;Observability 是&quot;我有能力在出新问题时,现场问出问题的答案&quot;。</p><h3 id="_2-2-known-unknowns-vs-unknown-unknowns" tabindex="-1">2.2 known unknowns vs unknown unknowns <a class="header-anchor" href="#_2-2-known-unknowns-vs-unknown-unknowns" aria-label="Permalink to &quot;2.2 known unknowns vs unknown unknowns&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>四种&quot;知识&quot;的分类(出自 Donald Rumsfeld):</span></span>
<span class="line"><span></span></span>
<span class="line"><span>         我知道我知道           我知道我不知道</span></span>
<span class="line"><span>       (known knowns)        (known unknowns)</span></span>
<span class="line"><span>            │                       │</span></span>
<span class="line"><span>            │                       │</span></span>
<span class="line"><span>  这部分被 Monitoring 覆盖     这部分被 Monitoring 覆盖</span></span>
<span class="line"><span>  → 用 dashboard 看现状         → 用告警提醒&quot;该问什么&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>       我不知道我知道          我不知道我不知道</span></span>
<span class="line"><span>     (unknown knowns)        (unknown unknowns)</span></span>
<span class="line"><span>            │                       │</span></span>
<span class="line"><span>            │                       │</span></span>
<span class="line"><span>   这部分要靠&quot;现场探索&quot;          这部分是 Observability</span></span>
<span class="line"><span>   → 系统里有数据但你没意识到   → 出新问题时能不能现场问出来</span></span></code></pre></div><p><strong>Monitoring 解决前两个象限,Observability 解决后两个象限</strong>——尤其右下角的&quot;unknown unknowns&quot;是 Observability 的核心价值。<strong>任何只覆盖前两个象限的系统都不能叫 Observability,只能叫 Monitoring + 告警</strong>。</p><h3 id="_2-3-具体差别长什么样" tabindex="-1">2.3 具体差别长什么样 <a class="header-anchor" href="#_2-3-具体差别长什么样" aria-label="Permalink to &quot;2.3 具体差别长什么样&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────┬──────────────────────────────────┐</span></span>
<span class="line"><span>│  Monitoring          │  Observability                   │</span></span>
<span class="line"><span>├──────────────────────┼──────────────────────────────────┤</span></span>
<span class="line"><span>│  预设 dashboard       │  ad-hoc 查询                     │</span></span>
<span class="line"><span>│  固定告警规则         │  动态切片                         │</span></span>
<span class="line"><span>│  阈值触发             │  关联分析                         │</span></span>
<span class="line"><span>│  按&quot;指标&quot;看           │  按&quot;事件&quot;看                       │</span></span>
<span class="line"><span>│  服务级聚合           │  请求级追踪                       │</span></span>
<span class="line"><span>│  事后看图             │  现场探索                         │</span></span>
<span class="line"><span>│  采集成本可控         │  采集成本可能爆炸                  │</span></span>
<span class="line"><span>│  适合&quot;日常运营&quot;       │  适合&quot;出新问题时定位&quot;              │</span></span>
<span class="line"><span>└──────────────────────┴──────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>实战意义:</span></span>
<span class="line"><span>   Monitoring 是&quot;我每天看看系统怎么样&quot; → 日常巡检</span></span>
<span class="line"><span>   Observability 是&quot;凌晨告警来了我能查清楚&quot; → 应急能力</span></span>
<span class="line"><span></span></span>
<span class="line"><span>两者不互斥,而是层层包含:</span></span>
<span class="line"><span>   Observability ⊃ Monitoring</span></span>
<span class="line"><span>   有 Observability 的系统自然能做 Monitoring</span></span>
<span class="line"><span>   只做 Monitoring 的系统达不到 Observability</span></span></code></pre></div><h3 id="_2-4-一个判定题" tabindex="-1">2.4 一个判定题 <a class="header-anchor" href="#_2-4-一个判定题" aria-label="Permalink to &quot;2.4 一个判定题&quot;">​</a></h3><p><strong>怎么判断你的系统有 Observability 还是只有 Monitoring</strong>?</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>判断题(必须 4 题都答 ✓ 才算有 Observability):</span></span>
<span class="line"><span></span></span>
<span class="line"><span>□ 出事时,你能 5 分钟内定位&quot;是哪个服务的问题&quot;?</span></span>
<span class="line"><span>□ 定位到服务后,你能 5 分钟内定位&quot;是哪个具体请求的问题&quot;?</span></span>
<span class="line"><span>□ 定位到请求后,你能 5 分钟内看到&quot;这个请求经过的所有下游 + 各自耗时&quot;?</span></span>
<span class="line"><span>□ 如果根因和&quot;业务参数&quot;有关(某个 user_id / 某个商品类目),</span></span>
<span class="line"><span>   你能现场切片找到那个具体特征?</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4 个 ✓ = 有 Observability</span></span>
<span class="line"><span>3 个 ✓ = 接近 Observability,缺一块</span></span>
<span class="line"><span>2 个 ✓ = 只有 Monitoring 加上了一点高级功能</span></span>
<span class="line"><span>&lt; 2 个 ✓ = 只是装了工具,本质是 Monitoring + 日志</span></span></code></pre></div><p><strong>国内中型团队 80% 在 2-3 个 ✓ 之间</strong>——装了三件套,但关联和查询能力不够。<strong>本系列第二层 8 篇要做的就是把这 4 个 ✓ 都拉满</strong>。</p><hr><h2 id="三、三件套-metrics-logs-traces" tabindex="-1">三、三件套:Metrics / Logs / Traces <a class="header-anchor" href="#三、三件套-metrics-logs-traces" aria-label="Permalink to &quot;三、三件套:Metrics / Logs / Traces&quot;">​</a></h2><p>可观测性的三件套是工业界事实标准——<strong>这三种数据类型各自擅长不同,组合起来才完整</strong>。</p><h3 id="_3-1-三件套的本质差别" tabindex="-1">3.1 三件套的本质差别 <a class="header-anchor" href="#_3-1-三件套的本质差别" aria-label="Permalink to &quot;3.1 三件套的本质差别&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                  Metrics      Logs        Traces</span></span>
<span class="line"><span>                  ───────      ────        ──────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>数据形态          数字+维度    文本事件    带因果关系的事件链</span></span>
<span class="line"><span>数据量            小 (聚合)    大 (高保真) 中 (跨服务采样)</span></span>
<span class="line"><span>查询粒度          聚合视图     单条事件    单次请求全链路</span></span>
<span class="line"><span>查询代价          低           中-高       中</span></span>
<span class="line"><span>存储代价          低           高          中</span></span>
<span class="line"><span>保留时长          14-90 天     7-30 天     1-7 天</span></span>
<span class="line"><span></span></span>
<span class="line"><span>擅长回答的问题:</span></span>
<span class="line"><span>  Metrics  ───→  &quot;整体趋势是什么样?&quot;</span></span>
<span class="line"><span>                  &quot;有多少请求 / 错误率多高 / P99 多久?&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Logs     ───→  &quot;这条具体记录里写了什么?&quot;</span></span>
<span class="line"><span>                  &quot;出错的请求 / 业务事件 / 调试输出?&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Traces   ───→  &quot;这次请求经过了什么,各自耗时多少?&quot;</span></span>
<span class="line"><span>                  &quot;跨服务的因果关系是什么?&quot;</span></span></code></pre></div><h3 id="_3-2-三件套的覆盖区与重叠区" tabindex="-1">3.2 三件套的覆盖区与重叠区 <a class="header-anchor" href="#_3-2-三件套的覆盖区与重叠区" aria-label="Permalink to &quot;3.2 三件套的覆盖区与重叠区&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                Metrics</span></span>
<span class="line"><span>              ┌──────────┐</span></span>
<span class="line"><span>              │  趋势     │</span></span>
<span class="line"><span>              │  聚合     │</span></span>
<span class="line"><span>              │  告警     │</span></span>
<span class="line"><span>              └────┬─────┘</span></span>
<span class="line"><span>                   │ Exemplar(指标里带 traceID)</span></span>
<span class="line"><span>                   │</span></span>
<span class="line"><span>              ┌────┴─────┐</span></span>
<span class="line"><span>              │          │</span></span>
<span class="line"><span>        Logs  │          │  Traces</span></span>
<span class="line"><span>        ┌─────┤          ├─────┐</span></span>
<span class="line"><span>        │ 事件 │ trace_id │ 链路 │</span></span>
<span class="line"><span>        │ 文本 │  关联    │ 因果 │</span></span>
<span class="line"><span>        │      │  字段    │      │</span></span>
<span class="line"><span>        └─────┴─────┬────┴─────┘</span></span>
<span class="line"><span>                    │</span></span>
<span class="line"><span>                    ▼</span></span>
<span class="line"><span>              重叠区(三件套关联键)</span></span>
<span class="line"><span>              这一区是 Observability</span></span>
<span class="line"><span>              真正发生的地方</span></span></code></pre></div><p><strong>三件套各自存在不叫可观测性,三件套通过关联键(trace_id)被串起来才叫可观测性</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>关联三件套的核心键:trace_id / span_id</span></span>
<span class="line"><span></span></span>
<span class="line"><span>在 Metrics 里:用 Exemplar 携带 trace_id</span></span>
<span class="line"><span>   → 看 dashboard 上一个慢点,能跳到那次请求的 trace</span></span>
<span class="line"><span></span></span>
<span class="line"><span>在 Logs 里:每条日志带上 trace_id</span></span>
<span class="line"><span>   → 看 trace 里某一步慢,能查那一步的具体日志</span></span>
<span class="line"><span></span></span>
<span class="line"><span>在 Traces 里:每个 span 包含 service / endpoint / 耗时</span></span>
<span class="line"><span>   → 看错误 metric,跳到 trace,跳到 log,全链路一气呵成</span></span></code></pre></div><p><strong>这个&quot;关联键贯穿&quot;是可观测性工程最值钱的一件事</strong>——11 篇(OpenTelemetry)会展开怎么落地。</p><h3 id="_3-3-各自擅长-不擅长" tabindex="-1">3.3 各自擅长 / 不擅长 <a class="header-anchor" href="#_3-3-各自擅长-不擅长" aria-label="Permalink to &quot;3.3 各自擅长 / 不擅长&quot;">​</a></h3><h4 id="_3-3-1-metrics-擅长-不擅长" tabindex="-1">3.3.1 Metrics 擅长 / 不擅长 <a class="header-anchor" href="#_3-3-1-metrics-擅长-不擅长" aria-label="Permalink to &quot;3.3.1 Metrics 擅长 / 不擅长&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Metrics 擅长:</span></span>
<span class="line"><span>   ✓ 回答&quot;系统整体怎么样&quot;(QPS / 错误率 / P99 延迟)</span></span>
<span class="line"><span>   ✓ 长期趋势(过去 30 天 / 90 天)</span></span>
<span class="line"><span>   ✓ 告警(数值越过阈值)</span></span>
<span class="line"><span>   ✓ 容量规划(看流量增长曲线)</span></span>
<span class="line"><span>   ✓ 成本极低(每个指标点几个字节)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Metrics 不擅长:</span></span>
<span class="line"><span>   ✗ 回答&quot;哪一次请求出问题&quot;</span></span>
<span class="line"><span>     → 因为是聚合,丢失了&quot;个体&quot;</span></span>
<span class="line"><span>   ✗ 携带任意字段(每个 label 都是 cardinality 代价,见后)</span></span>
<span class="line"><span>   ✗ 文本(描述 / 错误信息 / 上下文)</span></span>
<span class="line"><span>   ✗ 因果关系(哪个引起哪个)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>适用场景:</span></span>
<span class="line"><span>   - 仪表盘</span></span>
<span class="line"><span>   - 告警</span></span>
<span class="line"><span>   - SLO 计算</span></span>
<span class="line"><span>   - 容量规划</span></span></code></pre></div><h4 id="_3-3-2-logs-擅长-不擅长" tabindex="-1">3.3.2 Logs 擅长 / 不擅长 <a class="header-anchor" href="#_3-3-2-logs-擅长-不擅长" aria-label="Permalink to &quot;3.3.2 Logs 擅长 / 不擅长&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Logs 擅长:</span></span>
<span class="line"><span>   ✓ 回答&quot;具体发生了什么&quot;(完整文本 / 上下文)</span></span>
<span class="line"><span>   ✓ 业务事件(用户操作 / 订单流转)</span></span>
<span class="line"><span>   ✓ 调试信息(printf 大法)</span></span>
<span class="line"><span>   ✓ 审计追溯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Logs 不擅长:</span></span>
<span class="line"><span>   ✗ 整体趋势(从 1 亿条日志里聚合 QPS 是噩梦)</span></span>
<span class="line"><span>   ✗ 实时告警(延迟和成本都高)</span></span>
<span class="line"><span>   ✗ 跨服务关联(除非加 trace_id)</span></span>
<span class="line"><span>   ✗ 持久存储成本(每条几百字节)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>适用场景:</span></span>
<span class="line"><span>   - 调试 / 排查</span></span>
<span class="line"><span>   - 业务审计</span></span>
<span class="line"><span>   - 合规要求</span></span>
<span class="line"><span>   - 异常上下文</span></span></code></pre></div><h4 id="_3-3-3-traces-擅长-不擅长" tabindex="-1">3.3.3 Traces 擅长 / 不擅长 <a class="header-anchor" href="#_3-3-3-traces-擅长-不擅长" aria-label="Permalink to &quot;3.3.3 Traces 擅长 / 不擅长&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Traces 擅长:</span></span>
<span class="line"><span>   ✓ 回答&quot;这次请求经过了什么&quot;</span></span>
<span class="line"><span>   ✓ 跨服务因果关系</span></span>
<span class="line"><span>   ✓ 各步骤耗时分解</span></span>
<span class="line"><span>   ✓ 异常的&quot;传染路径&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Traces 不擅长:</span></span>
<span class="line"><span>   ✗ 整体统计(因为是采样,统计不准)</span></span>
<span class="line"><span>   ✗ 长期保留(数据量大)</span></span>
<span class="line"><span>   ✗ 业务字段(主要记技术调用)</span></span>
<span class="line"><span>   ✗ 没有 instrumentation 的服务</span></span>
<span class="line"><span></span></span>
<span class="line"><span>适用场景:</span></span>
<span class="line"><span>   - 跨服务排障</span></span>
<span class="line"><span>   - 性能下钻</span></span>
<span class="line"><span>   - 异常根因定位</span></span>
<span class="line"><span>   - 服务依赖图</span></span></code></pre></div><h3 id="_3-4-三件套的-优先建设-顺序" tabindex="-1">3.4 三件套的&quot;优先建设&quot;顺序 <a class="header-anchor" href="#_3-4-三件套的-优先建设-顺序" aria-label="Permalink to &quot;3.4 三件套的&quot;优先建设&quot;顺序&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>中型团队从零开始建可观测性,建议顺序:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第 1 步:Metrics</span></span>
<span class="line"><span>   → 投入最低,价值最高</span></span>
<span class="line"><span>   → Prometheus + Grafana,一周能上</span></span>
<span class="line"><span>   → 先有&quot;整体视图&quot;,再谈细节</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第 2 步:Logs</span></span>
<span class="line"><span>   → 大部分团队已经有(打日志是默认的)</span></span>
<span class="line"><span>   → 加结构化 + 集中收集</span></span>
<span class="line"><span>   → Loki / ELK 任选</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第 3 步:Traces</span></span>
<span class="line"><span>   → 投入相对大(代码侧需要 instrument)</span></span>
<span class="line"><span>   → 但 ROI 极高(跨服务排障)</span></span>
<span class="line"><span>   → OpenTelemetry + Tempo/Jaeger</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第 4 步:三件套关联</span></span>
<span class="line"><span>   → 在 Logs 里加 trace_id</span></span>
<span class="line"><span>   → 在 Metrics 里加 Exemplar</span></span>
<span class="line"><span>   → 让三件套从 Grafana 里能一键跳转</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第 5 步:Profile(下一节展开)</span></span>
<span class="line"><span>   → 不是必需,是&quot;能让效率再上一个台阶&quot;</span></span>
<span class="line"><span>   → 适合有 1000+ QPS / 10+ 服务的团队</span></span></code></pre></div><p><strong>不要一上来就 4 件套全上</strong>——Metrics 没用熟谈 Traces 是空中楼阁。<strong>90% 的事故 Metrics + 关联 Logs 已经能定位,Traces 是给剩下 10% 救命的</strong>。</p><hr><h2 id="四、第四件套-continuous-profiling" tabindex="-1">四、第四件套:Continuous Profiling <a class="header-anchor" href="#四、第四件套-continuous-profiling" aria-label="Permalink to &quot;四、第四件套:Continuous Profiling&quot;">​</a></h2><p>近几年(2020-2025)兴起的&quot;第四件套&quot;,<strong>很多人没听过,但已经在改变可观测性的边界</strong>。</p><h3 id="_4-1-为什么需要-profile" tabindex="-1">4.1 为什么需要 Profile <a class="header-anchor" href="#_4-1-为什么需要-profile" aria-label="Permalink to &quot;4.1 为什么需要 Profile&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>现有三件套的盲区:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Metrics 告诉你:</span></span>
<span class="line"><span>   &quot;服务 CPU 利用率 80%&quot;</span></span>
<span class="line"><span>   ← 但不告诉你&quot;哪个函数占了 80% 的 CPU&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Logs 告诉你:</span></span>
<span class="line"><span>   &quot;这个请求慢了 5 秒&quot;</span></span>
<span class="line"><span>   ← 但不告诉你&quot;这 5 秒里 CPU / IO / 锁 各自占多少&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Traces 告诉你:</span></span>
<span class="line"><span>   &quot;请求 → 服务 A → 服务 B → 数据库&quot;</span></span>
<span class="line"><span>   ← 但不告诉你&quot;在服务 A 内部哪个函数最耗时&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Profile 填补的是:&quot;函数级别的耗时归因&quot;</span></span>
<span class="line"><span>   - 哪个函数吃 CPU</span></span>
<span class="line"><span>   - 哪个函数分配内存</span></span>
<span class="line"><span>   - 哪个函数被锁阻塞</span></span></code></pre></div><h3 id="_4-2-continuous-profiling-是什么" tabindex="-1">4.2 Continuous Profiling 是什么 <a class="header-anchor" href="#_4-2-continuous-profiling-是什么" aria-label="Permalink to &quot;4.2 Continuous Profiling 是什么&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>传统 Profiling:</span></span>
<span class="line"><span>   - 出问题 → 手动启动 profiler → 采 1 分钟样本 → 分析</span></span>
<span class="line"><span>   - 问题:每次出事都要重头采样,且采样时性能影响大</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Continuous Profiling:</span></span>
<span class="line"><span>   - 始终采样(低频低开销,&lt; 1% CPU)</span></span>
<span class="line"><span>   - 数据持续存储(7-30 天)</span></span>
<span class="line"><span>   - 任何时刻都能&quot;回看历史&quot;</span></span>
<span class="line"><span>   - eBPF / pprof 实现采样</span></span></code></pre></div><h3 id="_4-3-工业界主流工具" tabindex="-1">4.3 工业界主流工具 <a class="header-anchor" href="#_4-3-工业界主流工具" aria-label="Permalink to &quot;4.3 工业界主流工具&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Pyroscope(Grafana 收购)</span></span>
<span class="line"><span>   - Go / Java / Python / Ruby 等多语言</span></span>
<span class="line"><span>   - 集成 Grafana</span></span>
<span class="line"><span>   - 开源 + SaaS 双形态</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Parca(Polar Signals)</span></span>
<span class="line"><span>   - eBPF-based,可以采&quot;任意语言&quot;</span></span>
<span class="line"><span>   - 不需要语言层 SDK</span></span>
<span class="line"><span>   - 开源</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Datadog Continuous Profiler</span></span>
<span class="line"><span>   - 商用,集成 Datadog</span></span>
<span class="line"><span>   - 不开源</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Pixie(New Relic 收购)</span></span>
<span class="line"><span>   - eBPF-based,kubernetes 原生</span></span>
<span class="line"><span>   - 不只 profile,也做 metrics / traces</span></span></code></pre></div><h3 id="_4-4-何时上-profile" tabindex="-1">4.4 何时上 Profile <a class="header-anchor" href="#_4-4-何时上-profile" aria-label="Permalink to &quot;4.4 何时上 Profile&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>该上的信号:</span></span>
<span class="line"><span>   ✓ Metrics 显示 CPU / 内存高,但找不到具体哪个函数</span></span>
<span class="line"><span>   ✓ 团队 &gt; 10 人,服务 &gt; 50 个</span></span>
<span class="line"><span>   ✓ 性能优化已经是日常工作(不只是出事时)</span></span>
<span class="line"><span>   ✓ 你的服务有&quot;长尾延迟&quot;需要解释</span></span>
<span class="line"><span></span></span>
<span class="line"><span>不该上的信号:</span></span>
<span class="line"><span>   ✗ 5 人小团队,5 个服务</span></span>
<span class="line"><span>     → 出事直接 pprof on-demand 也够</span></span>
<span class="line"><span>   ✗ 性能不是瓶颈(没人在乎)</span></span>
<span class="line"><span>   ✗ 还没把 Metrics / Logs / Traces 用熟</span></span></code></pre></div><p><strong>12 篇会展开 Continuous Profiling 的工程化,这里只是&quot;知道有这第四件套,以及它解决什么前三件套解决不了的问题&quot;</strong>。</p><hr><h2 id="五、cardinality-陷阱-这一篇的重点" tabindex="-1">五、Cardinality 陷阱(这一篇的重点) <a class="header-anchor" href="#五、cardinality-陷阱-这一篇的重点" aria-label="Permalink to &quot;五、Cardinality 陷阱(这一篇的重点)&quot;">​</a></h2><p>讲完三件套 + Profile 的概念,<strong>这一节讲一个非常具体的工程陷阱</strong>——它是中型团队上 Prometheus 第一年最容易踩的坑,而且踩了就是 P0。</p><h3 id="_5-1-什么是-cardinality" tabindex="-1">5.1 什么是 Cardinality <a class="header-anchor" href="#_5-1-什么是-cardinality" aria-label="Permalink to &quot;5.1 什么是 Cardinality&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Cardinality(基数)= 某个 label 的不同值的数量</span></span>
<span class="line"><span></span></span>
<span class="line"><span>例:</span></span>
<span class="line"><span>   指标 http_requests_total{service, endpoint, status}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   假设:</span></span>
<span class="line"><span>   - service 有 100 个不同值</span></span>
<span class="line"><span>   - endpoint 平均每个 service 有 20 个不同值</span></span>
<span class="line"><span>   - status 有 10 个不同值(200/201/4xx/5xx 等)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   这个指标的 cardinality:</span></span>
<span class="line"><span>   100 * 20 * 10 = 20,000 个 time series</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   每个 time series 在 Prometheus 里:</span></span>
<span class="line"><span>   - 占用约 1-3 KB 内存</span></span>
<span class="line"><span>   - 写入 IOPS / 网络流量都是单独计算</span></span>
<span class="line"><span>   - 查询时需要扫描</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   20,000 series → 约 50 MB 内存,可接受</span></span></code></pre></div><h3 id="_5-2-cardinality-爆炸的样子" tabindex="-1">5.2 Cardinality 爆炸的样子 <a class="header-anchor" href="#_5-2-cardinality-爆炸的样子" aria-label="Permalink to &quot;5.2 Cardinality 爆炸的样子&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>某天你心血来潮加了一个 label:</span></span>
<span class="line"><span>   http_requests_total{service, endpoint, status, user_id}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>假设你有 1,000,000 个 user</span></span>
<span class="line"><span></span></span>
<span class="line"><span>新的 cardinality:</span></span>
<span class="line"><span>   100 * 20 * 10 * 1,000,000 = 20,000,000,000 个 time series</span></span>
<span class="line"><span>                              = 200 亿!</span></span>
<span class="line"><span></span></span>
<span class="line"><span>200 亿 series 在 Prometheus 里:</span></span>
<span class="line"><span>   - 约 30 TB 内存 ← 不可能存得下</span></span>
<span class="line"><span>   - 写入吞吐量爆炸</span></span>
<span class="line"><span>   - 查询完全卡死</span></span>
<span class="line"><span></span></span>
<span class="line"><span>实际发生的:</span></span>
<span class="line"><span>   - Prometheus 进程 OOM(从 100GB 内存撑到机器限制)</span></span>
<span class="line"><span>   - 重启后再 OOM</span></span>
<span class="line"><span>   - 查询全部超时</span></span>
<span class="line"><span>   - 整个监控系统挂掉</span></span></code></pre></div><p><strong>这就是 cardinality 爆炸</strong>——一个 label 改错,一夜之间监控系统瘫痪。</p><h3 id="_5-3-哪些-label-是高危的" tabindex="-1">5.3 哪些 label 是高危的 <a class="header-anchor" href="#_5-3-哪些-label-是高危的" aria-label="Permalink to &quot;5.3 哪些 label 是高危的&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>低危(cardinality 低,可以做 label):</span></span>
<span class="line"><span>   ✓ service / app(几十到几百)</span></span>
<span class="line"><span>   ✓ method / endpoint(几十)</span></span>
<span class="line"><span>   ✓ status code(几十)</span></span>
<span class="line"><span>   ✓ environment(几个)</span></span>
<span class="line"><span>   ✓ region / az(十几个)</span></span>
<span class="line"><span>   ✓ error_type 分类(几十种)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>高危(cardinality 高,绝不能做 label):</span></span>
<span class="line"><span>   ✗ user_id(百万级)</span></span>
<span class="line"><span>   ✗ session_id(每次会话不同)</span></span>
<span class="line"><span>   ✗ request_id / trace_id(每次请求不同)</span></span>
<span class="line"><span>   ✗ ip(可能千万级)</span></span>
<span class="line"><span>   ✗ url(带 query string 的)</span></span>
<span class="line"><span>   ✗ exception_message(每次出错可能略不同)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>边界情况(看具体场景):</span></span>
<span class="line"><span>   △ tenant_id(多租户系统,可能几十到几千)</span></span>
<span class="line"><span>     → &lt; 100 可以,&gt; 1000 危险</span></span>
<span class="line"><span>   △ container_name(K8s 里,pod 重启后变)</span></span>
<span class="line"><span>     → 用 deployment 名替代,别用 pod 名</span></span>
<span class="line"><span>   △ version(可能几十个)</span></span>
<span class="line"><span>     → 多数情况可以,小心&quot;版本日积月累膨胀&quot;</span></span></code></pre></div><h3 id="_5-4-真实事故案例" tabindex="-1">5.4 真实事故案例 <a class="header-anchor" href="#_5-4-真实事故案例" aria-label="Permalink to &quot;5.4 真实事故案例&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>案例 A:trace_id 当 label</span></span>
<span class="line"><span></span></span>
<span class="line"><span>某团队上 OTel,工程师为了&quot;在 Prometheus 里能跳 trace&quot;,</span></span>
<span class="line"><span>加了一个 label: trace_id</span></span>
<span class="line"><span></span></span>
<span class="line"><span>每次请求生成新 trace_id → 每条请求都是新 series</span></span>
<span class="line"><span>QPS 1000 → 一分钟 60,000 个新 series</span></span>
<span class="line"><span>一小时 360 万 series,Prometheus 内存爆炸</span></span>
<span class="line"><span></span></span>
<span class="line"><span>修复:回滚 label,改用 Exemplar(只在某些样本上带 trace_id)</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>案例 B:user_id 在 metric 上</span></span>
<span class="line"><span></span></span>
<span class="line"><span>某团队为了&quot;看每个用户的 SLO&quot;,在 latency metric 上加 user_id</span></span>
<span class="line"><span></span></span>
<span class="line"><span>100 万用户上线第一天:</span></span>
<span class="line"><span>   Prometheus 内存从 10G 飙到 80G</span></span>
<span class="line"><span>   写入延迟从 &lt; 1s 升到 30s</span></span>
<span class="line"><span>   告警延迟到没意义</span></span>
<span class="line"><span>   挂了</span></span>
<span class="line"><span></span></span>
<span class="line"><span>修复:user_id 不放 metric,放 trace / log 里</span></span>
<span class="line"><span>       Metric 只看&quot;整体&quot; + &quot;按用户分桶(top 100 用户)&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>案例 C:exception_message 当 label</span></span>
<span class="line"><span></span></span>
<span class="line"><span>某团队的 error metric 上加了 error.message label</span></span>
<span class="line"><span>不同请求的 error message 略有不同(带参数)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  &quot;user 12345 not found&quot;</span></span>
<span class="line"><span>  &quot;user 12346 not found&quot;</span></span>
<span class="line"><span>  ...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>每个不同 user_id 出错都是新 series → cardinality 爆炸</span></span>
<span class="line"><span></span></span>
<span class="line"><span>修复:error.message → error.code(枚举值,有限种)</span></span>
<span class="line"><span>       原 message 保留在 log 里</span></span></code></pre></div><h3 id="_5-5-cardinality-预算估算公式" tabindex="-1">5.5 Cardinality 预算估算公式 <a class="header-anchor" href="#_5-5-cardinality-预算估算公式" aria-label="Permalink to &quot;5.5 Cardinality 预算估算公式&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Prometheus 单实例的 cardinality 预算估算:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  series 数量上限 ≈ 总内存(GB) * 100,000</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  例:32GB 内存的 Prometheus</span></span>
<span class="line"><span>      可承载约 3,200,000 series</span></span>
<span class="line"><span>      留 50% 余量 → 1,600,000 series 是安全上限</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  超过这个数量:</span></span>
<span class="line"><span>   - 写入开始慢</span></span>
<span class="line"><span>   - 查询超时</span></span>
<span class="line"><span>   - GC 占用 CPU</span></span>
<span class="line"><span>   - 最终 OOM</span></span>
<span class="line"><span></span></span>
<span class="line"><span>如何估算你的 cardinality:</span></span>
<span class="line"><span>  方法 1:Prometheus 自带查询</span></span>
<span class="line"><span>    prometheus_tsdb_head_series  ← 当前活跃 series 数</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  方法 2:看每个指标的 cardinality</span></span>
<span class="line"><span>    count by (__name__) ({__name__=~&quot;.+&quot;})</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  方法 3:Grafana Mimir / Cortex 的 cardinality API</span></span>
<span class="line"><span>    /api/v1/cardinality/active_series</span></span></code></pre></div><p><strong>实操建议</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>设 Cardinality 预算硬阈值:</span></span>
<span class="line"><span>   1M series   → 警告</span></span>
<span class="line"><span>   2M series   → 严重(必须人为介入)</span></span>
<span class="line"><span>   3M series   → 危险(开始拒新指标)</span></span>
<span class="line"><span>   4M series   → 拒服务(只保留核心指标)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>监控这个数字本身的告警:</span></span>
<span class="line"><span>   - prometheus_tsdb_head_series &gt; 2,000,000</span></span>
<span class="line"><span>   - 增长率 &gt; 10% / 天 → 报警</span></span></code></pre></div><h3 id="_5-6-怎么-在保留观测能力-的同时-控制-cardinality" tabindex="-1">5.6 怎么&quot;在保留观测能力&quot;的同时&quot;控制 cardinality&quot; <a class="header-anchor" href="#_5-6-怎么-在保留观测能力-的同时-控制-cardinality" aria-label="Permalink to &quot;5.6 怎么&quot;在保留观测能力&quot;的同时&quot;控制 cardinality&quot;&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原则 1:Metric 不放高 cardinality 字段</span></span>
<span class="line"><span>   - 高 cardinality 字段放 Logs / Traces</span></span>
<span class="line"><span>   - Metric 只保留聚合后的&quot;分桶&quot;(top N 用户、按租户分组)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>原则 2:用 Exemplar 桥接</span></span>
<span class="line"><span>   - Metric 不带 trace_id,但每个数据点可以附 1 个 trace_id</span></span>
<span class="line"><span>   - 看 Grafana panel 时能&quot;跳&quot; trace</span></span>
<span class="line"><span>   - Exemplar 不影响 cardinality</span></span>
<span class="line"><span></span></span>
<span class="line"><span>原则 3:Recording Rule 预聚合</span></span>
<span class="line"><span>   - 高 cardinality 的原始指标只短期保留</span></span>
<span class="line"><span>   - 用 Recording Rule 聚合成低 cardinality 的派生指标</span></span>
<span class="line"><span>   - 长期存储用聚合后的(06 / 07 篇会展开)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>原则 4:多实例隔离</span></span>
<span class="line"><span>   - 一个 Prometheus 不应该跨大业务线</span></span>
<span class="line"><span>   - 每个团队 / 每个业务一个 Prometheus</span></span>
<span class="line"><span>   - 用 Federation 或 VM-cluster 做全局视图(08 篇)</span></span></code></pre></div><hr><h2 id="六、可观测性的-3-个心智" tabindex="-1">六、可观测性的 3 个心智 <a class="header-anchor" href="#六、可观测性的-3-个心智" aria-label="Permalink to &quot;六、可观测性的 3 个心智&quot;">​</a></h2><p>讲完工具和陷阱,<strong>最后用 3 个心智收尾</strong>——这是衡量&quot;团队的可观测性成不成熟&quot;的核心维度。</p><h3 id="_6-1-心智-1-能定位故障-locate" tabindex="-1">6.1 心智 1:能定位故障(Locate) <a class="header-anchor" href="#_6-1-心智-1-能定位故障-locate" aria-label="Permalink to &quot;6.1 心智 1:能定位故障(Locate)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>最低限度:出事时能 5 分钟定位&quot;是哪个组件&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>具体能力:</span></span>
<span class="line"><span>   - 看到告警 → 知道&quot;哪个服务在烧&quot;</span></span>
<span class="line"><span>   - 看到服务 → 知道&quot;哪个 endpoint 在烧&quot;</span></span>
<span class="line"><span>   - 看到 endpoint → 知道&quot;是慢还是错&quot;</span></span>
<span class="line"><span>   - 看到慢 → 知道&quot;是哪个下游慢&quot;</span></span>
<span class="line"><span>   - 看到错 → 知道&quot;是哪类错&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>工具组合:</span></span>
<span class="line"><span>   Metrics 黄金 4 信号 dashboard</span></span>
<span class="line"><span>   + 服务依赖图(Service Map)</span></span>
<span class="line"><span>   + 错误堆栈聚合(Top N 错误类型)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>判断你是否做到:</span></span>
<span class="line"><span>   □ 出事时,5 分钟内能在 Grafana 上画出&quot;故障传播路径&quot;</span></span>
<span class="line"><span>   □ 知道&quot;哪些服务正常,哪些服务异常&quot;的边界</span></span>
<span class="line"><span>   □ 能给&quot;故障范围&quot;打一个准确的标签:核心 / 边缘 / 全局</span></span></code></pre></div><p><strong>这是可观测性的&quot;低阶能力&quot;,没做到这个,后面两个心智都谈不上</strong>。</p><h3 id="_6-2-心智-2-能解释为什么-explain" tabindex="-1">6.2 心智 2:能解释为什么(Explain) <a class="header-anchor" href="#_6-2-心智-2-能解释为什么-explain" aria-label="Permalink to &quot;6.2 心智 2:能解释为什么(Explain)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>进阶能力:出事后能 30 分钟讲清楚&quot;为什么&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>具体能力:</span></span>
<span class="line"><span>   - 定位到组件 → 能查到&quot;那一次/那段时间发生了什么&quot;</span></span>
<span class="line"><span>   - 能区分:发布引起的 / 流量引起的 / 依赖引起的 / 容量引起的</span></span>
<span class="line"><span>   - 能给出根因链(不是&quot;猜&quot;,是&quot;证据链&quot;)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>工具组合:</span></span>
<span class="line"><span>   定位能力(心智 1)</span></span>
<span class="line"><span>   + Logs 的精确查询</span></span>
<span class="line"><span>   + Traces 的下钻</span></span>
<span class="line"><span>   + 变更系统(发布历史 / 配置变更)</span></span>
<span class="line"><span>   + Profile(必要时)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>判断你是否做到:</span></span>
<span class="line"><span>   □ 复盘文档里&quot;根因&quot;能写到&quot;哪行代码 / 哪个配置 / 哪个依赖&quot;</span></span>
<span class="line"><span>   □ 不再用&quot;应该是 XX,但没确凿证据&quot;这种话</span></span>
<span class="line"><span>   □ 复盘和事故时间线能 100% 对得上</span></span></code></pre></div><p><strong>这是大多数中型团队卡住的台阶——出事能恢复但讲不清,导致同样的事故 6 周后再来</strong>。</p><h3 id="_6-3-心智-3-能预测下次-predict" tabindex="-1">6.3 心智 3:能预测下次(Predict) <a class="header-anchor" href="#_6-3-心智-3-能预测下次-predict" aria-label="Permalink to &quot;6.3 心智 3:能预测下次(Predict)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>高阶能力:从这次出事推测下次会出什么</span></span>
<span class="line"><span></span></span>
<span class="line"><span>具体能力:</span></span>
<span class="line"><span>   - 看到&quot;P99 在悄悄涨&quot; → 预测&quot;两周后会撞 SLO&quot;</span></span>
<span class="line"><span>   - 看到&quot;内存增长曲线&quot; → 预测&quot;X 天后会 OOM&quot;</span></span>
<span class="line"><span>   - 看到&quot;某个依赖的错误率上升&quot; → 预测&quot;它会拖垮我们&quot;</span></span>
<span class="line"><span>   - 看到&quot;流量增长&quot; → 预测&quot;什么时候需要扩容&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>工具组合:</span></span>
<span class="line"><span>   解释能力(心智 2)</span></span>
<span class="line"><span>   + 长期 Metrics(30-90 天)</span></span>
<span class="line"><span>   + 容量规划工具(30 篇会讲)</span></span>
<span class="line"><span>   + 趋势告警(不是阈值,是&quot;变化速度&quot;告警)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>判断你是否做到:</span></span>
<span class="line"><span>   □ 团队定期(月度)开&quot;健康趋势 review&quot;</span></span>
<span class="line"><span>   □ 容量瓶颈是&quot;预测&quot;的,不是&quot;撞上&quot;的</span></span>
<span class="line"><span>   □ 容量扩容是&quot;计划&quot;的,不是&quot;应急&quot;的</span></span>
<span class="line"><span>   □ 有&quot;早期预警告警&quot;——在用户感知前就动作</span></span></code></pre></div><p><strong>这是 Google SRE 团队的水平,中型团队能做到 50% 已经很好</strong>。</p><h3 id="_6-4-三个心智的层级关系" tabindex="-1">6.4 三个心智的层级关系 <a class="header-anchor" href="#_6-4-三个心智的层级关系" aria-label="Permalink to &quot;6.4 三个心智的层级关系&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>心智 1: Locate(能定位)</span></span>
<span class="line"><span>   ↑</span></span>
<span class="line"><span>   │ 必须先做到,才能往上走</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>心智 2: Explain(能解释)</span></span>
<span class="line"><span>   ↑</span></span>
<span class="line"><span>   │ 在能定位的基础上,加上&quot;证据链&quot;</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>心智 3: Predict(能预测)</span></span>
<span class="line"><span>   ↑</span></span>
<span class="line"><span>   │ 在能解释的基础上,看趋势 + 容量</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>   (最高级)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>中型团队的合理目标:</span></span>
<span class="line"><span>   - 6 个月做到 心智 1</span></span>
<span class="line"><span>   - 1 年做到 心智 2 一部分</span></span>
<span class="line"><span>   - 2 年做到 心智 3 雏形</span></span>
<span class="line"><span></span></span>
<span class="line"><span>不要直接追心智 3——基础没打好,预测都是猜测</span></span></code></pre></div><hr><h2 id="七、可观测性栈的全景图" tabindex="-1">七、可观测性栈的全景图 <a class="header-anchor" href="#七、可观测性栈的全景图" aria-label="Permalink to &quot;七、可观测性栈的全景图&quot;">​</a></h2><p>第二层 8 篇会展开每个组件,<strong>这里先给一张全景图,让你知道&quot;08-12 篇要堆什么东西&quot;</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                    可观测性栈(K8s 时代主流)                  │</span></span>
<span class="line"><span>├──────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│                                                              │</span></span>
<span class="line"><span>│  应用层(被观测)                                              │</span></span>
<span class="line"><span>│  ┌──────────────────┐ ┌──────────────────┐ ┌──────────────┐│</span></span>
<span class="line"><span>│  │   Java 应用       │ │   Go 应用         │ │  Node 应用   ││</span></span>
<span class="line"><span>│  │   + Micrometer    │ │   + Prom client   │ │  + Prom SDK  ││</span></span>
<span class="line"><span>│  │   + OTel SDK      │ │   + OTel SDK      │ │  + OTel SDK  ││</span></span>
<span class="line"><span>│  └─────────┬────────┘ └─────────┬────────┘ └───────┬──────┘│</span></span>
<span class="line"><span>│            │                    │                  │        │</span></span>
<span class="line"><span>│            ▼                    ▼                  ▼        │</span></span>
<span class="line"><span>│  采集层                                                       │</span></span>
<span class="line"><span>│  ┌──────────────────────────────────────────────────────┐  │</span></span>
<span class="line"><span>│  │  Metrics: Prometheus(scrape /metrics endpoint)        │  │</span></span>
<span class="line"><span>│  │  Logs:    Vector / Fluent Bit(stdout → 远程)         │  │</span></span>
<span class="line"><span>│  │  Traces:  OpenTelemetry Collector(OTLP)              │  │</span></span>
<span class="line"><span>│  │  Profile: Pyroscope Agent / Parca eBPF              │  │</span></span>
<span class="line"><span>│  └──────────────┬──────────────┬──────────────┬─────────┘  │</span></span>
<span class="line"><span>│                 │              │              │             │</span></span>
<span class="line"><span>│                 ▼              ▼              ▼             │</span></span>
<span class="line"><span>│  存储层                                                       │</span></span>
<span class="line"><span>│  ┌──────────────┐ ┌──────────────┐ ┌──────────────────┐    │</span></span>
<span class="line"><span>│  │ VictoriaMetric│ │  Loki / ELK  │ │  Tempo / Jaeger  │    │</span></span>
<span class="line"><span>│  │   / Mimir     │ │              │ │                  │    │</span></span>
<span class="line"><span>│  │   / Thanos    │ │              │ │                  │    │</span></span>
<span class="line"><span>│  │  (长存储)     │ │              │ │                  │    │</span></span>
<span class="line"><span>│  └──────┬───────┘ └──────┬───────┘ └─────────┬────────┘    │</span></span>
<span class="line"><span>│         │                │                   │              │</span></span>
<span class="line"><span>│         └────────────────┴───────────────────┘              │</span></span>
<span class="line"><span>│                          │                                  │</span></span>
<span class="line"><span>│                          ▼                                  │</span></span>
<span class="line"><span>│  查询/展示层                                                  │</span></span>
<span class="line"><span>│  ┌──────────────────────────────────────────────────┐      │</span></span>
<span class="line"><span>│  │            Grafana(统一 UI)                      │      │</span></span>
<span class="line"><span>│  │  Dashboard + Explore + Alerting + Tempo Trace UI │      │</span></span>
<span class="line"><span>│  └──────────────────────────────────────────────────┘      │</span></span>
<span class="line"><span>│                                                              │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────────────┘</span></span></code></pre></div><p><strong>这是 2025 年的主流栈,本系列 8 篇就是对这个图的每一块逐个讲清楚</strong>。</p><hr><h2 id="八、怎么落地-从无到有的-3-步" tabindex="-1">八、怎么落地:从无到有的 3 步 <a class="header-anchor" href="#八、怎么落地-从无到有的-3-步" aria-label="Permalink to &quot;八、怎么落地:从无到有的 3 步&quot;">​</a></h2><h3 id="_8-1-第-1-步-从-prometheus-grafana-开始" tabindex="-1">8.1 第 1 步:从 Prometheus + Grafana 开始 <a class="header-anchor" href="#_8-1-第-1-步-从-prometheus-grafana-开始" aria-label="Permalink to &quot;8.1 第 1 步:从 Prometheus + Grafana 开始&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>最小可行的可观测性 V0:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>部署:</span></span>
<span class="line"><span>   - 一个 Prometheus(&lt; 1M series 不用 federation)</span></span>
<span class="line"><span>   - 一个 Grafana</span></span>
<span class="line"><span>   - 一个 Alertmanager</span></span>
<span class="line"><span></span></span>
<span class="line"><span>埋点:</span></span>
<span class="line"><span>   - 每个服务暴露 /metrics(client_golang / Micrometer / prom-client)</span></span>
<span class="line"><span>   - 至少有黄金 4 信号(02 篇讲的)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>可观测层级:</span></span>
<span class="line"><span>   ✓ 能看整体趋势</span></span>
<span class="line"><span>   ✓ 能告警</span></span>
<span class="line"><span>   ✗ 不能定位单条请求</span></span>
<span class="line"><span>   ✗ 不能跨服务关联</span></span></code></pre></div><p><strong>这一步上线后,你已经超过 50% 的国内中型团队</strong>——很多团队连这一步都没做齐。</p><h3 id="_8-2-第-2-步-加结构化日志-集中收集" tabindex="-1">8.2 第 2 步:加结构化日志 + 集中收集 <a class="header-anchor" href="#_8-2-第-2-步-加结构化日志-集中收集" aria-label="Permalink to &quot;8.2 第 2 步:加结构化日志 + 集中收集&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>最小可行的可观测性 V1:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>加上:</span></span>
<span class="line"><span>   - 日志改成结构化(JSON,带 trace_id 字段)</span></span>
<span class="line"><span>   - Loki 或 ELK 集中收集</span></span>
<span class="line"><span>   - Grafana 接 Loki/ES 数据源</span></span>
<span class="line"><span></span></span>
<span class="line"><span>可观测层级:</span></span>
<span class="line"><span>   ✓ 整体趋势(V0)</span></span>
<span class="line"><span>   ✓ 告警(V0)</span></span>
<span class="line"><span>   ✓ 单条请求查询(从 trace_id 查)</span></span>
<span class="line"><span>   ✓ 错误堆栈聚合</span></span>
<span class="line"><span>   ✗ 还不能跨服务因果</span></span></code></pre></div><h3 id="_8-3-第-3-步-加-opentelemetry-traces" tabindex="-1">8.3 第 3 步:加 OpenTelemetry + Traces <a class="header-anchor" href="#_8-3-第-3-步-加-opentelemetry-traces" aria-label="Permalink to &quot;8.3 第 3 步:加 OpenTelemetry + Traces&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>最小可行的可观测性 V2:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>加上:</span></span>
<span class="line"><span>   - OpenTelemetry SDK 在所有服务接入</span></span>
<span class="line"><span>   - OTel Collector 集中接收 + 路由</span></span>
<span class="line"><span>   - Tempo 或 Jaeger 存 Traces</span></span>
<span class="line"><span>   - Grafana 接 Tempo</span></span>
<span class="line"><span></span></span>
<span class="line"><span>可观测层级:</span></span>
<span class="line"><span>   ✓ 整体 + 告警 + 单请求 + 跨服务因果</span></span>
<span class="line"><span>   ✓ &quot;三件套关联&quot;(metric Exemplar → trace → log)</span></span>
<span class="line"><span>   ✓ 能定位 + 能解释</span></span></code></pre></div><p><strong>做到这一步,你的团队就是国内可观测性的&quot;前 20%&quot;</strong>——再往下做 Profile / Predict 是锦上添花。</p><hr><h2 id="九、何时不该追求-全面可观测" tabindex="-1">九、何时不该追求&quot;全面可观测&quot; <a class="header-anchor" href="#九、何时不该追求-全面可观测" aria-label="Permalink to &quot;九、何时不该追求&quot;全面可观测&quot;&quot;">​</a></h2><p>不是所有团队都该上完整的可观测性栈。</p><h3 id="_9-1-不需要全栈可观测的场景" tabindex="-1">9.1 不需要全栈可观测的场景 <a class="header-anchor" href="#_9-1-不需要全栈可观测的场景" aria-label="Permalink to &quot;9.1 不需要全栈可观测的场景&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>场景 1:5 人小团队 + 单服务</span></span>
<span class="line"><span>   → SSH + 文件日志 + 简单 Prometheus 已经够</span></span>
<span class="line"><span>   → 上 OTel 是过度工程</span></span>
<span class="line"><span></span></span>
<span class="line"><span>场景 2:实验项目 / 内部工具</span></span>
<span class="line"><span>   → 没人 7x24 看,装了 dashboard 也没人看</span></span>
<span class="line"><span>   → 用云厂商自带的(CloudWatch / 阿里云 ARMS)更省事</span></span>
<span class="line"><span></span></span>
<span class="line"><span>场景 3:单台 VM 时代</span></span>
<span class="line"><span>   → 一台机器,日志直接看就行</span></span>
<span class="line"><span>   → 没必要 Loki / ELK</span></span>
<span class="line"><span></span></span>
<span class="line"><span>场景 4:预算极度紧张</span></span>
<span class="line"><span>   → 全栈可观测每月成本 ¥5000-50000</span></span>
<span class="line"><span>   → 月入百万以下的小厂,先看 ROI</span></span>
<span class="line"><span></span></span>
<span class="line"><span>场景 5:团队人手不够维护</span></span>
<span class="line"><span>   → 装了 Prometheus 没人调 PromQL</span></span>
<span class="line"><span>   → 装了 ELK 没人调 ES 配置</span></span>
<span class="line"><span>   → 与其装而不会用,不如不装</span></span></code></pre></div><h3 id="_9-2-何时该上的判断" tabindex="-1">9.2 何时该上的判断 <a class="header-anchor" href="#_9-2-何时该上的判断" aria-label="Permalink to &quot;9.2 何时该上的判断&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>触发可观测性投资的信号:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>✓ 单月发生 &gt; 2 次&quot;出事但说不清根因&quot;</span></span>
<span class="line"><span>✓ 团队规模 &gt; 8 人</span></span>
<span class="line"><span>✓ 微服务数量 &gt; 20 个</span></span>
<span class="line"><span>✓ QPS &gt; 1000</span></span>
<span class="line"><span>✓ 有 7x24 业务需求</span></span>
<span class="line"><span>✓ 客户开始问&quot;SLA 怎么定义&quot;</span></span>
<span class="line"><span>✓ 上次招到一个开发,他问&quot;你们有 Grafana 吗&quot;——这表示行业期望</span></span>
<span class="line"><span></span></span>
<span class="line"><span>满足 3 个以上 → 该上了</span></span>
<span class="line"><span>满足 5 个以上 → 你已经晚了</span></span></code></pre></div><hr><h2 id="十、踩坑提醒" tabindex="-1">十、踩坑提醒 <a class="header-anchor" href="#十、踩坑提醒" aria-label="Permalink to &quot;十、踩坑提醒&quot;">​</a></h2><ol><li><strong>以为&quot;装了 Prometheus 就是可观测性&quot;</strong>——只是 Monitoring 的一部分</li><li><strong>三件套各自为政,没关联键</strong>——trace_id 没透传,三件套就是三个孤岛</li><li><strong>user_id / trace_id 当 Prometheus label</strong>——cardinality 爆炸,系统挂掉</li><li><strong>没有 SLO 兜底的 dashboard</strong>——画了 100 个图没人看,没有&quot;健康/不健康&quot;判定线</li><li><strong>只看 metric 不看 trace</strong>——对慢请求无能为力,只能整体看不能下钻</li><li><strong>日志非结构化</strong>——查询难,没法和 trace 关联</li><li><strong>采集的指标太少</strong>——核心指标缺(JVM / DB / 队列),根因无从查</li><li><strong>采集的指标太多</strong>——cardinality 爆炸,Prometheus 拖垮</li><li><strong>告警满天飞</strong>——做 Monitoring 不做告警工程(15 篇会讲)</li><li><strong>没人会写 PromQL</strong>——会问问题但查不出答案</li><li><strong>dashboard 没人维护</strong>——上线时漂亮,半年后过期</li><li><strong>不区分 Monitoring 和 Observability</strong>——以为装更多工具就是 Observability,实际是要&quot;查询能力&quot;</li></ol><hr><h2 id="十一、本篇的硬指标" tabindex="-1">十一、本篇的硬指标 <a class="header-anchor" href="#十一、本篇的硬指标" aria-label="Permalink to &quot;十一、本篇的硬指标&quot;">​</a></h2><p>看完这一篇,你应该能在白板前讲清楚:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>□ Monitoring 和 Observability 的本质差别(known unknowns / unknown unknowns)</span></span>
<span class="line"><span>□ Metrics / Logs / Traces 各自擅长什么、不擅长什么</span></span>
<span class="line"><span>□ 三件套怎么通过 trace_id 关联,关联后能解决什么</span></span>
<span class="line"><span>□ Cardinality 爆炸是什么,user_id 当 label 为什么会让 Prometheus 挂</span></span>
<span class="line"><span>□ Cardinality 预算怎么估算(每 GB 内存约 10 万 series)</span></span>
<span class="line"><span>□ Continuous Profile 解决了三件套解决不了的什么问题</span></span>
<span class="line"><span>□ 可观测性的 3 个心智(Locate / Explain / Predict)</span></span>
<span class="line"><span>□ 中型团队的可观测性落地路线(V0/V1/V2 三步)</span></span></code></pre></div><p>并且能给自己团队<strong>做出 2 件具体动作</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 评估当前可观测性在哪个心智层级</span></span>
<span class="line"><span>   - Locate / Explain / Predict</span></span>
<span class="line"><span>   - 列出&quot;未达到&quot;的能力缺口</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 检查 Prometheus 的 cardinality 风险</span></span>
<span class="line"><span>   - 当前 series 数</span></span>
<span class="line"><span>   - 高风险 label 排查(user_id / trace_id / message)</span></span>
<span class="line"><span>   - 设 cardinality 预算硬告警</span></span></code></pre></div><hr><p>下一篇:<strong><code>04-生产系统的四个真相.md</code></strong>——讲完了可观测性的&quot;看见能力&quot;,最后一篇心智文章讲&quot;四个反直觉的真相&quot;:<strong>没有 100% 可用 / 失败是常态 / 自动化的陷阱 / 复盘的文化</strong>。这四件事工程师本能上不愿意接受——&quot;我的代码为什么会挂?&quot;&quot;我做的自动化为什么有坑?&quot;&quot;复盘为什么不能追个人责任?&quot;<strong>但接受了这四件事,你才真的进入了 SRE 工程师的心智</strong>。这是第一层的收尾,看完 4 篇,后面 30 篇的具体工程才有&quot;地基&quot;可踩。</p>`,126)])])}const g=n(e,[["render",i]]);export{h as __pageData,g as default};
